script:
frappe.ui.form.on("Grievance Box", {
    hostel_room: function(frm) {
        if (!frm.doc.hostel_room) return;

        frappe.db.get_value("Hostel Room", frm.doc.hostel_room,
            ["hostel", "hostel_block"]
        ).then(({message}) => {
            if (!message) return;

            frm.set_value("hostel", message.hostel);
            frm.set_value("hostel_block", message.hostel_block);

            frappe.db.get_value("Warden", { hostel: message.hostel, status: "Active" }, "name")
                .then(({message: w}) => {
                    if (w && w.name) {
                        frm.set_value("warden", w.name);
                    }
                });
        });
    },

    status: function(frm) {
        if (frm.doc.status === "Resolved" && !frm.doc.resolution_date) {
            frm.set_value("resolution_date", frappe.datetime.get_today());
        }
    }
});
